module adder_bcd(
    input  [3:0] A,
    input  [3:0] B,
    input        Cin,
    output [3:0] Sum,
    output       Cout
);

    wire [4:0] bin_sum;
    wire       correction_needed;
    wire [4:0] bcd_sum;

    assign bin_sum = A + B + Cin;
    assign correction_needed = (bin_sum > 5'd9);
    assign bcd_sum = correction_needed ? (bin_sum + 5'd6) : bin_sum;

    assign Sum = bcd_sum[3:0];
    assign Cout = correction_needed;

endmodule

