zero_shot.best_verilog:
module traffic_light(
    input  wire       rst_n,
    input  wire       clk,
    input  wire       pass_request,
    output wire [7:0] clock,
    output reg        red,
    output reg        yellow,
    output reg        green
);

parameter idle      = 2'd0;
parameter s1_red    = 2'd1;
parameter s2_yellow = 2'd2;
parameter s3_green  = 2'd3;

reg [7:0] cnt;
reg [1:0] state;
reg       p_red, p_yellow, p_green;

assign clock = cnt;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state    <= idle;
        p_red    <= 1'b0;
        p_yellow <= 1'b0;
        p_green  <= 1'b0;
    end else begin
        case (state)
            idle: begin
