    input  clk,
    input  rst_n,
    output clk_div
);

    localparam integer MUL2_DIV_CLK = 7;

    reg [2:0] cnt_p;
    reg [2:0] cnt_n;

    reg clk_p;
    reg clk_n;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt_p <= 3'd0;
            clk_p <= 1'b0;
        end else begin
            if (cnt_p == MUL2_DIV_CLK-1)
                cnt_p <= 3'd0;
            else
                cnt_p <= cnt_p + 3'd1;

            case (cnt_p)
                3'd0: clk_p <= 1'b1;
                3'd4: clk_p <= 1'b0;
                3'd6: clk_p <= 1'b1;
                default: clk_p <= clk_p;
            endcase
        end
    end

    always @(negedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt_n <= 3'd0;
            clk_n <= 1'b0;
